   "out-data" : "update ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        :root{\\\\n          --frawo-forest:#064e3b;\\\\n          --frawo-forest-dark:#052e16;\\\\n          --frawo-mint:#ecfdf5;\\\\n          --frawo-accent:#a855f7;\\\\n          --frawo-ink:#0f172a;\\\\n          --frawo-soft:#475569;\\\\n          --frawo-line:#d1fae5;\\\\n        }\\\\n        .frawo-home{background:linear-gradient(180deg,#f8fffb 0%,#ffffff 100%);}\\\\n        .frawo-home .container{position:relative;z-index:1;}\\\\n        .frawo-kicker{letter-spacing:.22em;text-transform:uppercase;color:var(--frawo-accent);font-weight:800;font-size:.8rem;}\\\\n        .frawo-hero{position:relative;overflow:hidden;padding:7rem 0 5.5rem;background:radial-gradient(circle at 80% 20%, rgba(168,85,247,.18), transparent 28%),radial-gradient(circle at 15% 15%, rgba(6,78,59,.08), transparent 28%),linear-gradient(135deg,#f0fdf4 0%,#ffffff 58%,#ecfdf5 100%);}\\\\n        .frawo-hero-title{color:var(--frawo-ink);font-weight:900;line-height:.94;font-size:clamp(2.8rem,6vw,5.4rem);}\\\\n        .frawo-hero-sub{color:var(--frawo-soft);font-size:1.1rem;max-width:42rem;line-height:1.65;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.62rem .95rem;border-radius:999px;background:#ffffffd9;border:1px solid var(--frawo-line);color:var(--frawo-forest);font-weight:700;}\\\\n        .frawo-chip:before{content:\\\\\"\\\\\";width:.55rem;height:.55rem;border-radius:50%;background:var(--frawo-accent);}\\\\n        .frawo-primary{background:var(--frawo-forest);border-color:var(--frawo-forest);}\\\\n        .frawo-primary:hover{background:var(--frawo-forest-dark);border-color:var(--frawo-forest-dark);}\\\\n        .frawo-secondary{border:2px solid var(--frawo-forest);color:var(--frawo-forest);background:transparent;}\\\\n        .frawo-secondary:hover{background:var(--frawo-forest);color:#fff;}\\\\n        .frawo-photo-stack{display:grid;grid-template-columns:1.15fr .85fr;gap:1rem;align-items:stretch;}\\\\n        .frawo-photo-main,.frawo-photo-side{border-radius:1.6rem;overflow:hidden;box-shadow:0 22px 55px rgba(15,23,42,.15);background:#e2e8f0;}\\\\n        .frawo-photo-main img,.frawo-photo-side img{width:100%;height:100%;object-fit:cover;display:block;}\\\\n        .frawo-photo-side{display:grid;grid-template-rows:1fr 1fr;gap:1rem;background:transparent;box-shadow:none;}\\\\n        .frawo-photo-side .frawo-photo-card{border-radius:1.3rem;overflow:hidden;box-shadow:0 18px 44px rgba(15,23,42,.14);background:#e2e8f0;}\\\\n        .frawo-section{padding:5rem 0;}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.5rem;background:#ffffff;box-shadow:0 22px 50px rgba(15,23,42,.07);}\\\\n        .frawo-card .frawo-number{font-size:2rem;font-weight:900;color:var(--frawo-accent);line-height:1;}\\\\n        .frawo-card h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-band{background:linear-gradient(135deg,var(--frawo-forest-dark) 0%,var(--frawo-forest) 100%);color:#ecfdf5;border-radius:1.8rem;padding:2.75rem;}\\\\n        .frawo-band .frawo-band-kicker{color:#a7f3d0;letter-spacing:.18em;text-transform:uppercase;font-weight:700;font-size:.8rem;}\\\\n        .frawo-step{display:grid;grid-template-columns:auto 1fr;gap:1rem;align-items:start;}\\\\n        .frawo-step-no{width:2.5rem;height:2.5rem;border-radius:999px;background:#ffffff14;border:1px solid #ffffff33;display:flex;align-items:center;justify-content:center;font-weight:800;}\\\\n        .frawo-proof{border-radius:1.8rem;background:#f8fafc;border:1px solid #e2e8f0;padding:2rem;}\\\\n        .frawo-proof h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-mini-gallery{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;}\\\\n        .frawo-mini-gallery img{width:100%;height:13rem;object-fit:cover;border-radius:1.2rem;box-shadow:0 16px 36px rgba(15,23,42,.12);}\\\\n        .frawo-contact-card{border:none;border-radius:1.6rem;background:#ffffff;box-shadow:0 22px 50px rgba(15,23,42,.08);}\\\\n        @media (max-width: 991px){.frawo-photo-stack{grid-template-columns:1fr;gap:1rem;}.frawo-photo-side{grid-template-columns:1fr 1fr;grid-template-rows:none;}.frawo-mini-gallery{grid-template-columns:1fr;}.frawo-mini-gallery img{height:16rem;}}\\\\n        @media (max-width: 767px){.frawo-hero{padding:5.25rem 0 4rem;}.frawo-band{padding:1.5rem;}.frawo-photo-side{grid-template-columns:1fr;}}\\\\n      </style>\\\\n      <section class=\\\\\"frawo-home frawo-hero\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\">FraWo GbR | Eventdienstleister</div>\\\\n              <h1 class=\\\\\"frawo-hero-title mb-4\\\\\">Eventbetrieb mit technischer Praezision.</h1>\\\\n              <p class=\\\\\"frawo-hero-sub mb-4\\\\\">FraWo plant, betreut und stabilisiert Veranstaltungen, Medientechnik und digitale Kontaktpfade. Wir treten als Technikfachkraefte und Macher auf: klar im Ablauf, sauber in der Kommunikation, verlaesslich im Livebetrieb.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">Projekt anfragen</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-secondary\\\\\" href=\\\\\"/contactus\\\\\">Kontakt</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Eventtechnik</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Ablaufsteuerung</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Website &amp; Infofluss</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-photo-stack\\\\\">\\\\n                <div class=\\\\\"frawo-photo-main\\\\\"><img src=\\\\\"/web/image/1803\\\\\" alt=\\\\\"FraWo Eventmotiv Hauptbild\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                <div class=\\\\\"frawo-photo-side\\\\\">\\\\n                  <div class=\\\\\"frawo-photo-card\\\\\"><img src=\\\\\"/web/image/1798\\\\\" alt=\\\\\"FraWo Eventmotiv Detail 1\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                  <div class=\\\\\"frawo-photo-card\\\\\"><img src=\\\\\"/web/image/1801\\\\\" alt=\\\\\"FraWo Eventmotiv Detail 2\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-card p-4\\\\\"><div class=\\\\\"frawo-number mb-3\\\\\">01</div><h3 class=\\\\\"h4 mb-3\\\\\">Technische Umsetzung</h3><p class=\\\\\"mb-0\\\\\">Ton, Licht, Zuspieler, Displays, Streaming und Signalwege werden als belastbares Setup gedacht, nicht als loses Sammelsurium.</p></div></div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-card p-4\\\\\"><div class=\\\\\"frawo-number mb-3\\\\\">02</div><h3 class=\\\\\"h4 mb-3\\\\\">Event-Webseite &amp; Kommunikation</h3><p class=\\\\\"mb-0\\\\\">Landingpages, Kontaktpfade, Team-Infos und Veranstaltungsupdates bleiben klar, schnell und technisch sauber erreichbar.</p></div></div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-card p-4\\\\\"><div class=\\\\\"frawo-number mb-3\\\\\">03</div><h3 class=\\\\\"h4 mb-3\\\\\">Hintergrund, der haelt</h3><p class=\\\\\"mb-0\\\\\">Dokumente, Freigaben, Materiallisten und Nachlauf werden so organisiert, dass der Livebetrieb nicht an Kleinkram scheitert.</p></div></div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band\\\\\">\\\\n            <div class=\\\\\"row g-4 align-items-start\\\\\">\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <div class=\\\\\"frawo-band-kicker mb-3\\\\\">Arbeitsweise</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Kein BlaBla. Ein sauberer Betriebsweg.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo arbeitet wie ein verantwortlicher Technikpartner: kurz im Briefing, klar in den Entscheidungen und praesent im entscheidenden Moment vor Ort oder im digitalen Pfad.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"d-grid gap-3\\\\\">\\\\n                  <div class=\\\\\"frawo-step\\\\\"><div class=\\\\\"frawo-step-no\\\\\">01</div><div><strong>Briefing:</strong> Ziel, Publikum, Techniklage und kritische Punkte werden ohne Umwege festgezogen.</div></div>\\\\n                  <div class=\\\\\"frawo-step\\\\\"><div class=\\\\\"frawo-step-no\\\\\">02</div><div><strong>Aufbauplan:</strong> Signalweg, Verantwortlichkeiten, Seitenstruktur und Kommunikationspfad stehen vor dem Livegang.</div></div>\\\\n                  <div class=\\\\\"frawo-step\\\\\"><div class=\\\\\"frawo-step-no\\\\\">03</div><div><strong>Livebetrieb:</strong> Technik, Updates und Ansprechpartner bleiben unter Last kontrollierbar.</div></div>\\\\n                  <div class=\\\\\"frawo-step\\\\\"><div class=\\\\\"frawo-step-no\\\\\">04</div><div><strong>Nachlauf:</strong> Material, Dokumentation und naechste Schritte werden sauber uebergeben statt liegen gelassen.</div></div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-5\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\">Positionierung</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Technikfachkraefte und Macher fuer reale Auftritte.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">FraWo tritt nicht als Dekor auf, sondern als belastbarer Eventdienstleister. Wer eine funktionierende Techniklinie, klare Informationswege und einen souveraenen Auftritt braucht, braucht vor allem saubere Entscheidungen und eine Mannschaft, die liefert.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">Deshalb verbinden wir Eventbetrieb, Medientechnik und digitale Sichtbarkeit in einem konsistenten Pfad statt in drei getrennten Baustellen.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <div class=\\\\\"frawo-proof\\\\\">\\\\n                <div class=\\\\\"row g-4 align-items-center\\\\\">\\\\n                  <div class=\\\\\"col-lg-7\\\\\">\\\\n                    <h3 class=\\\\\"h3 mb-3\\\\\">Wofuer FraWo gebucht wird</h3>\\\\n                    <ul class=\\\\\"list-unstyled mb-0 d-grid gap-2\\\\\">\\\\n                      <li><strong>Veranstaltungen:</strong> technische Betreuung, Zuspielung, Ablauf und sichtbare Ruhe im Livefenster.</li>\\\\n                      <li><strong>Teams &amp; Organisationen:</strong> eine Website, die informiert statt zu verwirren.</li>\\\\n                      <li><strong>Projektpartner:</strong> ein Ansprechpartner, der Technik und Umsetzung zusammenhaelt.</li>\\\\n                      <li><strong>Nachlauf:</strong> Dateien, Infos und offene Punkte bleiben sortiert statt zu versickern.</li>\\\\n                    </ul>\\\\n                  </div>\\\\n                  <div class=\\\\\"col-lg-5\\\\\">\\\\n                    <div class=\\\\\"frawo-mini-gallery\\\\\">\\\\n                      <img src=\\\\\"/web/image/1797\\\\\" alt=\\\\\"FraWo Galerie 1\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                      <img src=\\\\\"/web/image/1805\\\\\" alt=\\\\\"FraWo Galerie 2\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                      <img src=\\\\\"/web/image/1806\\\\\" alt=\\\\\"FraWo Galerie 3\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                    </div>\\\\n                  </div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\">Kontakt</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Wenn es konkret werden soll, direkt melden.</h2>\\\\n              <p class=\\\\\"mb-0\\\\\">Am schnellsten geht der Einstieg per Mail. Fuer die schnelle Rueckfrage ist der Telefonpfad da. Lieber ein klares Anliegen als fuenf lose Ideen.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Projektstart</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">Mail mit Termin, Ort, Zielbild und technischer Lage reicht fuer den ersten Aufschlag. Danach ziehen wir den passenden Weg auf.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn btn-lg frawo-secondary\\\\\" href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\"}' where id=3636;\nupdate ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<t name=\\\\\"Contact Us\\\\\" t-name=\\\\\"website.contactus\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        :root{--frawo-forest:#064e3b;--frawo-forest-dark:#052e16;--frawo-accent:#a855f7;--frawo-ink:#0f172a;--frawo-soft:#475569;}\\\\n        .frawo-contact-page{background:linear-gradient(180deg,#f8fffb 0%,#ffffff 100%);}\\\\n        .frawo-contact-page .container{position:relative;z-index:1;}\\\\n        .frawo-kicker{letter-spacing:.22em;text-transform:uppercase;color:var(--frawo-accent);font-weight:800;font-size:.8rem;}\\\\n        .frawo-contact-hero{position:relative;overflow:hidden;padding:6rem 0 4.5rem;background:radial-gradient(circle at 75% 18%, rgba(168,85,247,.16), transparent 25%),linear-gradient(135deg,#052e16 0%,#064e3b 58%,#14532d 100%);color:#ecfdf5;}\\\\n        .frawo-contact-hero:before{content:\\\\\"\\\\\";position:absolute;inset:auto -8% -35% auto;width:26rem;height:26rem;border-radius:50%;background:radial-gradient(circle,#a855f744 0%,#a855f700 72%);}\\\\n        .frawo-contact-title{font-weight:900;line-height:.96;font-size:clamp(2.5rem,5vw,4.5rem);}\\\\n        .frawo-contact-sub{font-size:1.08rem;line-height:1.7;max-width:40rem;color:#dcfce7;}\\\\n        .frawo-contact-photo{border-radius:1.6rem;overflow:hidden;box-shadow:0 22px 60px rgba(15,23,42,.2);}\\\\n        .frawo-contact-photo img{width:100%;height:100%;object-fit:cover;display:block;min-height:19rem;}\\\\n        .frawo-contact-section{padding:4.75rem 0;}\\\\n        .frawo-contact-card{height:100%;border:none;border-radius:1.5rem;background:#ffffff;box-shadow:0 22px 50px rgba(15,23,42,.08);}\\\\n        .frawo-contact-card h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-contact-card p,.frawo-contact-card li{color:var(--frawo-soft);}\\\\n        .frawo-contact-cta{background:var(--frawo-forest);border-color:var(--frawo-forest);}\\\\n        .frawo-contact-cta:hover{background:var(--frawo-forest-dark);border-color:var(--frawo-forest-dark);}\\\\n        .frawo-contact-list{list-style:none;padding:0;margin:0;display:grid;gap:.9rem;}\\\\n        .frawo-contact-list li{display:flex;gap:.8rem;align-items:flex-start;}\\\\n        .frawo-contact-list li:before{content:\\\\\"\\\\\";margin-top:.45rem;width:.55rem;height:.55rem;border-radius:50%;background:var(--frawo-accent);flex:0 0 auto;}\\\\n      </style>\\\\n      <section class=\\\\\"frawo-contact-page frawo-contact-hero\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\" style=\\\\\"color:#c4b5fd;\\\\\">Kontakt</div>\\\\n              <h1 class=\\\\\"frawo-contact-title mb-3\\\\\">Projektstart ohne Umwege.</h1>\\\\n              <p class=\\\\\"frawo-contact-sub mb-4\\\\\">Wenn eine Veranstaltung, ein Techniksetup oder eine Event-Seite sauber aufgesetzt werden soll, reicht eine klare Anfrage. FraWo antwortet lieber konkret als kuenstlich aufgeblasen.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                <a class=\\\\\"btn btn-light btn-lg\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">info@frawo-tech.de</a>\\\\n                <a class=\\\\\"btn btn-outline-light btn-lg\\\\\" href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5\\\\\">\\\\n              <div class=\\\\\"frawo-contact-photo\\\\\"><img src=\\\\\"/web/image/1803\\\\\" alt=\\\\\"FraWo Eventkontakt Bild\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-contact-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-contact-card p-4\\\\\"><h3 class=\\\\\"h4 mb-3\\\\\">Mail</h3><p class=\\\\\"mb-3\\\\\">Der schnellste Weg fuer Anfragen, Termine, Material und erste Eckdaten.</p><p class=\\\\\"mb-0\\\\\"><a href=\\\\\"mailto:info@frawo-tech.de\\\\\">info@frawo-tech.de</a></p></div></div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-contact-card p-4\\\\\"><h3 class=\\\\\"h4 mb-3\\\\\">Telefon</h3><p class=\\\\\"mb-3\\\\\">Wenn etwas schnell geklaert werden muss oder der Live-Termin naeher rueckt.</p><p class=\\\\\"mb-0\\\\\"><a href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a></p></div></div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-contact-card p-4\\\\\"><h3 class=\\\\\"h4 mb-3\\\\\">Standort</h3><p class=\\\\\"mb-3\\\\\">FraWo arbeitet von Weissensberg aus und betreut Einsaetze mit klarer Technik- und Kommunikationslinie.</p><p class=\\\\\"mb-0\\\\\">Rothkreuz 14<br/>88138 Weissensberg</p></div></div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-contact-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\">Typische Themen</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Wobei FraWo direkt sinnvoll wird</h2>\\\\n              <ul class=\\\\\"frawo-contact-list\\\\\">\\\\n                <li>Technische Betreuung fuer Veranstaltung, Livestream oder Medienbuehne.</li>\\\\n                <li>Event-Seite mit Kontaktpfad, Updates und klarer Information fuer Team oder Publikum.</li>\\\\n                <li>Signalweg, Zuspielung und Ablauf muessen an einem Termin zuverlaessig stehen.</li>\\\\n                <li>Ein Ansprechpartner soll Umsetzung, Kommunikation und Nachlauf zusammenhalten.</li>\\\\n              </ul>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Fuer die erste Mail hilfreich</h3>\\\\n                <ul class=\\\\\"frawo-contact-list\\\\\">\\\\n                  <li>Wann und wo findet der Termin statt?</li>\\\\n                  <li>Was soll technisch und kommunikativ stehen?</li>\\\\n                  <li>Welche Rolle spielt die Website oder das Update-Fenster?</li>\\\\n                  <li>Gibt es feste Risiken, Fristen oder Ansprechpartner?</li>\\\\n                </ul>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3 mt-4\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-contact-cta\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">Projekt anfragen</a>\\\\n                  <a class=\\\\\"btn btn-outline-secondary\\\\\" href=\\\\\"/\\\\\">Zur Startseite</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\"}' where id=3637;\nupdate ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<t name=\\\\\"Home\\\\\" t-name=\\\\\"website.homepage\\\\\">\\\\n  <t t-call=\\\\\"website.layout\\\\\">\\\\n    <t t-set=\\\\\"pageName\\\\\" t-value=\\\\\"''homepage''\\\\\"/>\\\\n    <div id=\\\\\"wrap\\\\\" class=\\\\\"oe_structure\\\\\">\\\\n      <style>\\\\n        :root{\\\\n          --frawo-forest:#064e3b;\\\\n          --frawo-forest-dark:#052e16;\\\\n          --frawo-mint:#ecfdf5;\\\\n          --frawo-accent:#a855f7;\\\\n          --frawo-ink:#0f172a;\\\\n          --frawo-soft:#475569;\\\\n          --frawo-line:#d1fae5;\\\\n        }\\\\n        .frawo-home{background:linear-gradient(180deg,#f8fffb 0%,#ffffff 100%);}\\\\n        .frawo-home .container{position:relative;z-index:1;}\\\\n        .frawo-kicker{letter-spacing:.22em;text-transform:uppercase;color:var(--frawo-accent);font-weight:800;font-size:.8rem;}\\\\n        .frawo-hero{position:relative;overflow:hidden;padding:7rem 0 5.5rem;background:radial-gradient(circle at 80% 20%, rgba(168,85,247,.18), transparent 28%),radial-gradient(circle at 15% 15%, rgba(6,78,59,.08), transparent 28%),linear-gradient(135deg,#f0fdf4 0%,#ffffff 58%,#ecfdf5 100%);}\\\\n        .frawo-hero-title{color:var(--frawo-ink);font-weight:900;line-height:.94;font-size:clamp(2.8rem,6vw,5.4rem);}\\\\n        .frawo-hero-sub{color:var(--frawo-soft);font-size:1.1rem;max-width:42rem;line-height:1.65;}\\\\n        .frawo-chip{display:inline-flex;align-items:center;gap:.55rem;padding:.62rem .95rem;border-radius:999px;background:#ffffffd9;border:1px solid var(--frawo-line);color:var(--frawo-forest);font-weight:700;}\\\\n        .frawo-chip:before{content:\\\\\"\\\\\";width:.55rem;height:.55rem;border-radius:50%;background:var(--frawo-accent);}\\\\n        .frawo-primary{background:var(--frawo-forest);border-color:var(--frawo-forest);}\\\\n        .frawo-primary:hover{background:var(--frawo-forest-dark);border-color:var(--frawo-forest-dark);}\\\\n        .frawo-secondary{border:2px solid var(--frawo-forest);color:var(--frawo-forest);background:transparent;}\\\\n        .frawo-secondary:hover{background:var(--frawo-forest);color:#fff;}\\\\n        .frawo-photo-stack{display:grid;grid-template-columns:1.15fr .85fr;gap:1rem;align-items:stretch;}\\\\n        .frawo-photo-main,.frawo-photo-side{border-radius:1.6rem;overflow:hidden;box-shadow:0 22px 55px rgba(15,23,42,.15);background:#e2e8f0;}\\\\n        .frawo-photo-main img,.frawo-photo-side img{width:100%;height:100%;object-fit:cover;display:block;}\\\\n        .frawo-photo-side{display:grid;grid-template-rows:1fr 1fr;gap:1rem;background:transparent;box-shadow:none;}\\\\n        .frawo-photo-side .frawo-photo-card{border-radius:1.3rem;overflow:hidden;box-shadow:0 18px 44px rgba(15,23,42,.14);background:#e2e8f0;}\\\\n        .frawo-section{padding:5rem 0;}\\\\n        .frawo-card{height:100%;border:none;border-radius:1.5rem;background:#ffffff;box-shadow:0 22px 50px rgba(15,23,42,.07);}\\\\n        .frawo-card .frawo-number{font-size:2rem;font-weight:900;color:var(--frawo-accent);line-height:1;}\\\\n        .frawo-card h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-band{background:linear-gradient(135deg,var(--frawo-forest-dark) 0%,var(--frawo-forest) 100%);color:#ecfdf5;border-radius:1.8rem;padding:2.75rem;}\\\\n        .frawo-band .frawo-band-kicker{color:#a7f3d0;letter-spacing:.18em;text-transform:uppercase;font-weight:700;font-size:.8rem;}\\\\n        .frawo-step{display:grid;grid-template-columns:auto 1fr;gap:1rem;align-items:start;}\\\\n        .frawo-step-no{width:2.5rem;height:2.5rem;border-radius:999px;background:#ffffff14;border:1px solid #ffffff33;display:flex;align-items:center;justify-content:center;font-weight:800;}\\\\n        .frawo-proof{border-radius:1.8rem;background:#f8fafc;border:1px solid #e2e8f0;padding:2rem;}\\\\n        .frawo-proof h3{color:var(--frawo-ink);font-weight:800;}\\\\n        .frawo-mini-gallery{display:grid;grid-template-columns:repeat(3,1fr);gap:1rem;}\\\\n        .frawo-mini-gallery img{width:100%;height:13rem;object-fit:cover;border-radius:1.2rem;box-shadow:0 16px 36px rgba(15,23,42,.12);}\\\\n        .frawo-contact-card{border:none;border-radius:1.6rem;background:#ffffff;box-shadow:0 22px 50px rgba(15,23,42,.08);}\\\\n        @media (max-width: 991px){.frawo-photo-stack{grid-template-columns:1fr;gap:1rem;}.frawo-photo-side{grid-template-columns:1fr 1fr;grid-template-rows:none;}.frawo-mini-gallery{grid-template-columns:1fr;}.frawo-mini-gallery img{height:16rem;}}\\\\n        @media (max-width: 767px){.frawo-hero{padding:5.25rem 0 4rem;}.frawo-band{padding:1.5rem;}.frawo-photo-side{grid-template-columns:1fr;}}\\\\n      </style>\\\\n      <section class=\\\\\"frawo-home frawo-hero\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row align-items-center g-5\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\">FraWo GbR | Eventdienstleister</div>\\\\n              <h1 class=\\\\\"frawo-hero-title mb-4\\\\\">Eventbetrieb mit technischer Praezision.</h1>\\\\n              <p class=\\\\\"frawo-hero-sub mb-4\\\\\">FraWo plant, betreut und stabilisiert Veranstaltungen, Medientechnik und digitale Kontaktpfade. Wir treten als Technikfachkraefte und Macher auf: klar im Ablauf, sauber in der Kommunikation, verlaesslich im Livebetrieb.</p>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-3 mb-4\\\\\">\\\\n                <a class=\\\\\"btn btn-primary btn-lg frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">Projekt anfragen</a>\\\\n                <a class=\\\\\"btn btn-lg frawo-secondary\\\\\" href=\\\\\"/contactus\\\\\">Kontakt</a>\\\\n              </div>\\\\n              <div class=\\\\\"d-flex flex-wrap gap-2\\\\\">\\\\n                <span class=\\\\\"frawo-chip\\\\\">Eventtechnik</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Ablaufsteuerung</span>\\\\n                <span class=\\\\\"frawo-chip\\\\\">Website &amp; Infofluss</span>\\\\n              </div>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-photo-stack\\\\\">\\\\n                <div class=\\\\\"frawo-photo-main\\\\\"><img src=\\\\\"/web/image/1803\\\\\" alt=\\\\\"FraWo Eventmotiv Hauptbild\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                <div class=\\\\\"frawo-photo-side\\\\\">\\\\n                  <div class=\\\\\"frawo-photo-card\\\\\"><img src=\\\\\"/web/image/1798\\\\\" alt=\\\\\"FraWo Eventmotiv Detail 1\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                  <div class=\\\\\"frawo-photo-card\\\\\"><img src=\\\\\"/web/image/1801\\\\\" alt=\\\\\"FraWo Eventmotiv Detail 2\\\\\" loading=\\\\\"lazy\\\\\"/></div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4\\\\\">\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-card p-4\\\\\"><div class=\\\\\"frawo-number mb-3\\\\\">01</div><h3 class=\\\\\"h4 mb-3\\\\\">Technische Umsetzung</h3><p class=\\\\\"mb-0\\\\\">Ton, Licht, Zuspieler, Displays, Streaming und Signalwege werden als belastbares Setup gedacht, nicht als loses Sammelsurium.</p></div></div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-card p-4\\\\\"><div class=\\\\\"frawo-number mb-3\\\\\">02</div><h3 class=\\\\\"h4 mb-3\\\\\">Event-Webseite &amp; Kommunikation</h3><p class=\\\\\"mb-0\\\\\">Landingpages, Kontaktpfade, Team-Infos und Veranstaltungsupdates bleiben klar, schnell und technisch sauber erreichbar.</p></div></div>\\\\n            <div class=\\\\\"col-lg-4 d-flex\\\\\"><div class=\\\\\"card frawo-card p-4\\\\\"><div class=\\\\\"frawo-number mb-3\\\\\">03</div><h3 class=\\\\\"h4 mb-3\\\\\">Hintergrund, der haelt</h3><p class=\\\\\"mb-0\\\\\">Dokumente, Freigaben, Materiallisten und Nachlauf werden so organisiert, dass der Livebetrieb nicht an Kleinkram scheitert.</p></div></div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"frawo-band\\\\\">\\\\n            <div class=\\\\\"row g-4 align-items-start\\\\\">\\\\n              <div class=\\\\\"col-lg-5\\\\\">\\\\n                <div class=\\\\\"frawo-band-kicker mb-3\\\\\">Arbeitsweise</div>\\\\n                <h2 class=\\\\\"display-6 mb-3\\\\\">Kein BlaBla. Ein sauberer Betriebsweg.</h2>\\\\n                <p class=\\\\\"mb-0\\\\\">FraWo arbeitet wie ein verantwortlicher Technikpartner: kurz im Briefing, klar in den Entscheidungen und praesent im entscheidenden Moment vor Ort oder im digitalen Pfad.</p>\\\\n              </div>\\\\n              <div class=\\\\\"col-lg-7\\\\\">\\\\n                <div class=\\\\\"d-grid gap-3\\\\\">\\\\n                  <div class=\\\\\"frawo-step\\\\\"><div class=\\\\\"frawo-step-no\\\\\">01</div><div><strong>Briefing:</strong> Ziel, Publikum, Techniklage und kritische Punkte werden ohne Umwege festgezogen.</div></div>\\\\n                  <div class=\\\\\"frawo-step\\\\\"><div class=\\\\\"frawo-step-no\\\\\">02</div><div><strong>Aufbauplan:</strong> Signalweg, Verantwortlichkeiten, Seitenstruktur und Kommunikationspfad stehen vor dem Livegang.</div></div>\\\\n                  <div class=\\\\\"frawo-step\\\\\"><div class=\\\\\"frawo-step-no\\\\\">03</div><div><strong>Livebetrieb:</strong> Technik, Updates und Ansprechpartner bleiben unter Last kontrollierbar.</div></div>\\\\n                  <div class=\\\\\"frawo-step\\\\\"><div class=\\\\\"frawo-step-no\\\\\">04</div><div><strong>Nachlauf:</strong> Material, Dokumentation und naechste Schritte werden sauber uebergeben statt liegen gelassen.</div></div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-5\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\">Positionierung</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Technikfachkraefte und Macher fuer reale Auftritte.</h2>\\\\n              <p class=\\\\\"mb-3\\\\\">FraWo tritt nicht als Dekor auf, sondern als belastbarer Eventdienstleister. Wer eine funktionierende Techniklinie, klare Informationswege und einen souveraenen Auftritt braucht, braucht vor allem saubere Entscheidungen und eine Mannschaft, die liefert.</p>\\\\n              <p class=\\\\\"mb-0\\\\\">Deshalb verbinden wir Eventbetrieb, Medientechnik und digitale Sichtbarkeit in einem konsistenten Pfad statt in drei getrennten Baustellen.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-7\\\\\">\\\\n              <div class=\\\\\"frawo-proof\\\\\">\\\\n                <div class=\\\\\"row g-4 align-items-center\\\\\">\\\\n                  <div class=\\\\\"col-lg-7\\\\\">\\\\n                    <h3 class=\\\\\"h3 mb-3\\\\\">Wofuer FraWo gebucht wird</h3>\\\\n                    <ul class=\\\\\"list-unstyled mb-0 d-grid gap-2\\\\\">\\\\n                      <li><strong>Veranstaltungen:</strong> technische Betreuung, Zuspielung, Ablauf und sichtbare Ruhe im Livefenster.</li>\\\\n                      <li><strong>Teams &amp; Organisationen:</strong> eine Website, die informiert statt zu verwirren.</li>\\\\n                      <li><strong>Projektpartner:</strong> ein Ansprechpartner, der Technik und Umsetzung zusammenhaelt.</li>\\\\n                      <li><strong>Nachlauf:</strong> Dateien, Infos und offene Punkte bleiben sortiert statt zu versickern.</li>\\\\n                    </ul>\\\\n                  </div>\\\\n                  <div class=\\\\\"col-lg-5\\\\\">\\\\n                    <div class=\\\\\"frawo-mini-gallery\\\\\">\\\\n                      <img src=\\\\\"/web/image/1797\\\\\" alt=\\\\\"FraWo Galerie 1\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                      <img src=\\\\\"/web/image/1805\\\\\" alt=\\\\\"FraWo Galerie 2\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                      <img src=\\\\\"/web/image/1806\\\\\" alt=\\\\\"FraWo Galerie 3\\\\\" loading=\\\\\"lazy\\\\\"/>\\\\n                    </div>\\\\n                  </div>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n      <section class=\\\\\"frawo-section pt-0\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-5 align-items-center\\\\\">\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"frawo-kicker mb-3\\\\\">Kontakt</div>\\\\n              <h2 class=\\\\\"display-6 mb-3\\\\\" style=\\\\\"color:var(--frawo-ink);font-weight:900;\\\\\">Wenn es konkret werden soll, direkt melden.</h2>\\\\n              <p class=\\\\\"mb-0\\\\\">Am schnellsten geht der Einstieg per Mail. Fuer die schnelle Rueckfrage ist der Telefonpfad da. Lieber ein klares Anliegen als fuenf lose Ideen.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-6\\\\\">\\\\n              <div class=\\\\\"card frawo-contact-card p-4 p-lg-5\\\\\">\\\\n                <h3 class=\\\\\"h3 mb-3\\\\\">Projektstart</h3>\\\\n                <p class=\\\\\"mb-4\\\\\">Mail mit Termin, Ort, Zielbild und technischer Lage reicht fuer den ersten Aufschlag. Danach ziehen wir den passenden Weg auf.</p>\\\\n                <div class=\\\\\"d-flex flex-wrap gap-3\\\\\">\\\\n                  <a class=\\\\\"btn btn-primary frawo-primary\\\\\" href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\">info@frawo-tech.de</a>\\\\n                  <a class=\\\\\"btn btn-lg frawo-secondary\\\\\" href=\\\\\"tel:+4915155243164\\\\\">+49 151 55243164</a>\\\\n                </div>\\\\n              </div>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </t>\\\\n</t>\\\\n\"}' where id=3644;\nupdate ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<data inherit_id=\\\\\"website.placeholder_header_call_to_action\\\\\" name=\\\\\"Header Call to Action\\\\\" active=\\\\\"True\\\\\">\\\\n  <xpath expr=\\\\\".\\\\\" position=\\\\\"inside\\\\\">\\\\n    <li t-attf-class=\\\\\"#{_item_class}\\\\\">\\\\n      <div t-attf-class=\\\\\"oe_structure oe_structure_solo #{_div_class}\\\\\">\\\\n        <section class=\\\\\"oe_unremovable oe_unmovable s_text_block\\\\\" data-snippet=\\\\\"s_text_block\\\\\" data-name=\\\\\"Text\\\\\">\\\\n          <div class=\\\\\"container\\\\\">\\\\n            <a href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\" class=\\\\\"oe_unremovable btn btn-primary btn_cta\\\\\">Projekt anfragen</a>\\\\n          </div>\\\\n        </section>\\\\n      </div>\\\\n    </li>\\\\n  </xpath>\\\\n</data>\\\\n\"}' where id=3726;\nupdate ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<data inherit_id=\\\\\"website.layout\\\\\" name=\\\\\"Default\\\\\" active=\\\\\"True\\\\\">\\\\n  <xpath expr=\\\\\"//div[@id=''footer'']\\\\\" position=\\\\\"replace\\\\\">\\\\n    <div id=\\\\\"footer\\\\\" class=\\\\\"oe_structure oe_structure_solo\\\\\" t-ignore=\\\\\"true\\\\\" t-if=\\\\\"not no_footer\\\\\">\\\\n      <section class=\\\\\"s_text_block pt40 pb24\\\\\" data-snippet=\\\\\"s_text_block\\\\\" data-name=\\\\\"Text\\\\\" style=\\\\\"background:#052e16; color:#ecfdf5;\\\\\">\\\\n        <div class=\\\\\"container\\\\\">\\\\n          <div class=\\\\\"row g-4 align-items-start\\\\\">\\\\n            <div class=\\\\\"col-lg-4\\\\\">\\\\n              <h4 class=\\\\\"mb-3\\\\\" style=\\\\\"color:#ffffff;\\\\\">FraWo GbR</h4>\\\\n              <p class=\\\\\"mb-0\\\\\">Eventdienstleistung mit technischer Disziplin: Medientechnik, Ablaufsteuerung, Website- und Informationspfade fuer Auftritte, die live sauber stehen muessen.</p>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-3\\\\\">\\\\n              <h5 class=\\\\\"mb-3\\\\\" style=\\\\\"color:#a7f3d0;\\\\\">Direktwege</h5>\\\\n              <ul class=\\\\\"list-unstyled mb-0\\\\\">\\\\n                <li class=\\\\\"mb-2\\\\\"><a href=\\\\\"/\\\\\" style=\\\\\"color:#ffffff;\\\\\">Startseite</a></li>\\\\n                <li class=\\\\\"mb-2\\\\\"><a href=\\\\\"/contactus\\\\\" style=\\\\\"color:#ffffff;\\\\\">Kontakt</a></li>\\\\n                <li class=\\\\\"mb-2\\\\\"><a href=\\\\\"/privacy\\\\\" style=\\\\\"color:#ffffff;\\\\\">Datenschutz</a></li>\\\\n                <li><a href=\\\\\"mailto:info@frawo-tech.de\\\\\" style=\\\\\"color:#ffffff;\\\\\">Projekt anfragen</a></li>\\\\n              </ul>\\\\n            </div>\\\\n            <div class=\\\\\"col-lg-5\\\\\">\\\\n              <h5 class=\\\\\"mb-3\\\\\" style=\\\\\"color:#a7f3d0;\\\\\">Kontakt</h5>\\\\n              <ul class=\\\\\"list-unstyled mb-0\\\\\">\\\\n                <li class=\\\\\"mb-2\\\\\">Rothkreuz 14, 88138 Weissensberg</li>\\\\n                <li class=\\\\\"mb-2\\\\\"><a href=\\\\\"tel:+4915155243164\\\\\" style=\\\\\"color:#ffffff;\\\\\">+49 151 55243164</a></li>\\\\n                <li><a href=\\\\\"mailto:info@frawo-tech.de\\\\\" style=\\\\\"color:#ffffff;\\\\\">info@frawo-tech.de</a></li>\\\\n              </ul>\\\\n            </div>\\\\n          </div>\\\\n        </div>\\\\n      </section>\\\\n    </div>\\\\n  </xpath>\\\\n</data>\\\\n\"}' where id=4405;\nupdate ir_ui_view set active='t', arch_db=E'{\"de_DE\": \"\\\\n<data inherit_id=\\\\\"website.placeholder_header_call_to_action\\\\\" name=\\\\\"Header Call to Action\\\\\" active=\\\\\"True\\\\\">\\\\n  <xpath expr=\\\\\".\\\\\" position=\\\\\"inside\\\\\">\\\\n    <li t-attf-class=\\\\\"#{_item_class}\\\\\">\\\\n      <div t-attf-class=\\\\\"oe_structure oe_structure_solo #{_div_class}\\\\\" class=\\\\\"oe_structure oe_structure_solo\\\\\">\\\\n        <section class=\\\\\"oe_unremovable oe_unmovable s_text_block o_colored_level\\\\\" data-snippet=\\\\\"s_text_block\\\\\" data-name=\\\\\"Text\\\\\" style=\\\\\"background-image: none;\\\\\">\\\\n          <div class=\\\\\"container\\\\\">\\\\n            <a href=\\\\\"mailto:info@frawo-tech.de?subject=Projektanfrage%20FraWo\\\\\" class=\\\\\"oe_unremovable btn btn-primary btn_cta\\\\\" data-bs-original-title=\\\\\"\\\\\" title=\\\\\"\\\\\">Projekt anfragen</a>\\\\n          </div>\\\\n        </section>\\\\n      </div>\\\\n    </li>\\\\n  </xpath>\\\\n</data>\\\\n\"}' where id=4462;\nupdate website_menu set name='{\"de_DE\": \"Kontakt\"}'::jsonb, url='/contactus', page_id=3, new_window='false' where id=3;\nupdate website_menu set name='{\"de_DE\": \"Kontakt\"}'::jsonb, url='/contactus', page_id=3, new_window='false' where id=6;\nupdate website set domain=NULL, homepage_url='/' where id=1;\n",
